const SANITY_PROJECT="ehwjnjr2",SANITY_DATASET="production",SANITY_API_VER="2024-01-01",SANITY_CDN=`https://${SANITY_PROJECT}.apicdn.sanity.io/v${SANITY_API_VER}/data/query/${SANITY_DATASET}`;async function sanityFetch(e,a={}){let t=`${SANITY_CDN}?query=${encodeURIComponent(e)}`;for(const[r,s]of Object.entries(a))t+=`&$${encodeURIComponent(r)}=${encodeURIComponent(JSON.stringify(s))}`;try{const r=await fetch(t);if(!r.ok)throw new Error(`HTTP ${r.status}`);return(await r.json())?.result??null}catch(r){return console.warn("[CMS] Fetch failed:",r.message),null}}window.CMS={fetchArticleBySlug(e,a="en"){const t=a==="de";return sanityFetch(`*[_type == "newsArticle" && slug.current == $slug][0] {
      _id,
      "id": slug.current,
      "title": ${t?"coalesce(titleDe, title)":"title"},
      category,
      "categoryLabel": ${t?"coalesce(categoryLabelDe, categoryLabel)":"categoryLabel"},
      "date": date,
      "dateISO": date,
      "imageUrl": image.asset->url + "?w=900&auto=format&q=80",
      alt,
      "excerpt": ${t?"coalesce(excerptDe, excerpt)":"excerpt"},
      "content": ${t?"select(defined(contentDe) => array::join(contentDe[_type=='block']{'h':select(style=='h2'=>'<h2>'+array::join(children[].text,'')+ '</h2>',style=='h3'=>'<h3>'+array::join(children[].text,'')+ '</h3>',style=='blockquote'=>'<blockquote>'+array::join(children[].text,'')+ '</blockquote>','<p>'+array::join(children[].text,'')+ '</p>')}.h,''),content)":"content"},
      seo
    }`,{slug:e})}};
